VALUES
  ('optician-moex-02669', 'optician', 'optician-moex-106-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關隱形眼鏡清潔液中防腐劑的敘述，下列何者錯誤？', '["隱形眼鏡清潔液中通常含有防腐劑", "氯化苯二甲烴銨（benzalkonium chloride）對角膜組織無毒性", "防腐劑對細菌有抑制生長的作用，但對黴菌的抑制效果差", "含氯化苯二甲烴銨（benzalkonium chloride）的清潔液會增加隱形眼鏡的厭水性，使沉積物更容易沾黏"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:37+00:00", "source_pdf_sha1": "62c9a3599d15", "answer_pdf_sha1": "1ebc5f4e77dc", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 45, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
