  ('optician-moex-02671', 'optician', 'optician-moex-106-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關長期配戴硬式隱形眼鏡後裂隙燈檢查之敘述何者錯誤？', '["12點及6點鐘方位出現螢光點狀染色與周邊角膜乾燥有關", "弧狀（arc）的周邊角膜螢光染色與鏡片中央基弧與周邊邊弧交融（blending）不良有關", "當3點及9點鐘方位出現螢光點狀染色時，須考慮將鏡片直徑變大並將鏡片周邊邊挑（edge lift）變高", "輪部新生血管的產生與鏡片直徑過大或低的周邊邊挑設計有關"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:37+00:00", "source_pdf_sha1": "62c9a3599d15", "answer_pdf_sha1": "1ebc5f4e77dc", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 47, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02672', 'optician', 'optician-moex-106-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '一眼散光軸度為150°，試戴軟式散光隱形眼鏡，若鏡片上6點鐘方向的定位刻度線停留在7點鐘方向， 訂片時其散光軸度應為何？', '["180°", "165°", "135°", "120°"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:37+00:00", "source_pdf_sha1": "62c9a3599d15", "answer_pdf_sha1": "1ebc5f4e77dc", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 48, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02673', 'optician', 'optician-moex-106-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '硬式隱形眼鏡驗配時，若配戴過鬆，可能出現的情形為何？①鏡片下方有氣泡在中央區  ②鏡片下方有氣', '["螢光染色時含螢光的淚液在中央較多", "螢光染色時含螢光的淚液在周邊較多", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:37+00:00", "source_pdf_sha1": "62c9a3599d15", "answer_pdf_sha1": "1ebc5f4e77dc", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 49, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02674', 'optician', 'optician-moex-106-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關隱形眼鏡清潔液之敘述，下列何者錯誤？', '["須接近中性酸鹼度", "須為高滲透壓", "須有抑制細菌生長的功效", "須含緩衝液，調節酸鹼度"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:37+00:00", "source_pdf_sha1": "62c9a3599d15", "answer_pdf_sha1": "1ebc5f4e77dc", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 50, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02675', 'optician', 'optician-moex-106-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '關於高含水量相較於低含水量軟式水膠（hydrogels）隱形眼鏡之敘述，下列何者正確？', '["抗撕裂能力較好，耐用", "較柔軟", "較不容易受環境影響", "較不透氧"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "21dccecf40fb", "answer_pdf_sha1": "332b43e00546", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02676', 'optician', 'optician-moex-106-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '關於隱形眼鏡的透氧率（Dk, oxygen permeability）和傳氧率（Dk/L, oxygen transmissibility），下列敘述 何者正確？', '["傳氧率與鏡片厚度成正比", "軟式水膠隱形眼鏡的傳氧率比硬式透氣隱形眼鏡（RGP）高", "透氧率與鏡片厚度成反比", "透氧率為擴散係數與溶解係數的乘積"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "21dccecf40fb", "answer_pdf_sha1": "332b43e00546", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02677', 'optician', 'optician-moex-106-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '關於隱形眼鏡的濕潤度（wettability），下列敘述何者錯誤？', '["軟式隱形眼鏡的濕潤度和舒適度有關", "隱形眼鏡材質的接觸角（contact angle）越大，親水性越佳", "硬式透氣隱形眼鏡的矽含量越大，厭水性增加", "隱形眼鏡清潔液中添加乙二醇（glycol）等黏稠劑，可提升隱形眼鏡濕潤度"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "21dccecf40fb", "answer_pdf_sha1": "332b43e00546", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02678', 'optician', 'optician-moex-106-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '不直接碰觸角膜的鞏膜片（scleral lens），一般直徑大小範圍為何？', '["<10 mm", "8～12 mm", "10～14 mm", "15～25 mm"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "21dccecf40fb", "answer_pdf_sha1": "332b43e00546", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
